/**
 * Returns the Round of 32 matchups for the 8 third-place teams.
 * @param qualifyingGroups - Array of 8 group letters whose 3rd-place teams advanced (e.g. ["E","F","G","H","I","J","K","L"])
 */
export function getMatchups(qualifyingGroups: string[]): ThirdPlaceMatchup[] {
  const key = [...qualifyingGroups].sort().join("");
  const result = COMBINATIONS[key];
  if (!result) {
    throw new Error(`No combination found for qualifying groups: ${key}`);
  }
  return result;
}
